import{_ as n,c as r,o as i,a1 as t}from"./chunks/framework.DILC4Csi.js";const c=JSON.parse('{"title":"Benutzervereinbarung: Dienstrichtlinien | OpenCodeDocs","description":"Erfahren Sie mehr über die Dienstrichtlinien, die Urheberrechte und die Haftungsausschlüsse der OpenCodeDocs-Benutzervereinbarung sowie die Rechte und Pflichten beider Parteien.","frontmatter":{"title":"Benutzervereinbarung: Dienstrichtlinien | OpenCodeDocs","sidebarTitle":"Regeln in 5 Minuten","subtitle":"Benutzervereinbarung: Dienstrichtlinien","description":"Erfahren Sie mehr über die Dienstrichtlinien, die Urheberrechte und die Haftungsausschlüsse der OpenCodeDocs-Benutzervereinbarung sowie die Rechte und Pflichten beider Parteien."},"headers":[],"relativePath":"de/terms.md","filePath":"de/terms.md"}'),a={name:"de/terms.md"};function s(u,e,l,o,g,h){return i(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="benutzervereinbarung" tabindex="-1">Benutzervereinbarung <a class="header-anchor" href="#benutzervereinbarung" aria-label="Permalink to &quot;Benutzervereinbarung&quot;">​</a></h1><p>Zuletzt aktualisiert am: 2026-01-01<br> Inkrafttreten: 2026-01-01</p><p>Willkommen bei OpenCodeDocs! Bevor Sie unsere Dienste nutzen, lesen Sie bitte diese Benutzervereinbarung (im Folgenden &quot;Vereinbarung&quot; genannt) sorgfältig durch. Die Nutzung unserer Dienste bedeutet, dass Sie sich an die Bedingungen dieser Vereinbarung halten.</p><h2 id="_1-beschreibung-der-dienste" tabindex="-1">1. Beschreibung der Dienste <a class="header-anchor" href="#_1-beschreibung-der-dienste" aria-label="Permalink to &quot;1. Beschreibung der Dienste&quot;">​</a></h2><p>OpenCodeDocs ist eine offene Plattform, die sich auf Tutorials für KI-Tools spezialisiert hat und folgende Dienste anbietet:</p><ul><li><strong>Tutorial-Inhalte</strong>: Anleitungen zur Nutzung von Open-Source-KI-Tools (wie Claude Code, Cursor, LangChain usw.)</li><li><strong>Code-Verifizierung</strong>: Automatische Verifizierung der Ausführbarkeit von Code in Tutorials basierend auf Quellcode-Repositories</li><li><strong>Community-Funktionen</strong>: Benutzer können über GitHub an Content-Beiträgen und Diskussionen teilnehmen</li></ul><p>Wir behalten uns das Recht vor, Teile oder alle Dienste jederzeit ohne Vorankündigung zu ändern, auszusetzen oder zu beenden.</p><h2 id="_2-konto-registrierung-und-verwaltung" tabindex="-1">2. Konto-Registrierung und -Verwaltung <a class="header-anchor" href="#_2-konto-registrierung-und-verwaltung" aria-label="Permalink to &quot;2. Konto-Registrierung und -Verwaltung&quot;">​</a></h2><h3 id="registrierungsvoraussetzungen" tabindex="-1">Registrierungsvoraussetzungen <a class="header-anchor" href="#registrierungsvoraussetzungen" aria-label="Permalink to &quot;Registrierungsvoraussetzungen&quot;">​</a></h3><ul><li>Sie müssen mindestens 16 Jahre alt sein (oder das gesetzliche Alter in Ihrer Region erreicht haben)</li><li>Sie müssen echte, genaue Registrierungsinformationen angeben</li><li>Jeder Benutzer darf nur ein Konto registrieren</li></ul><h3 id="kontosicherheit" tabindex="-1">Kontosicherheit <a class="header-anchor" href="#kontosicherheit" aria-label="Permalink to &quot;Kontosicherheit&quot;">​</a></h3><ul><li>Sie sind verantwortlich für die sichere Aufbewahrung Ihrer Kontozugangsdaten und dürfen diese nicht mit anderen teilen</li><li>Wenn Sie feststellen, dass Ihr Konto unbefugt genutzt wurde, kontaktieren Sie uns bitte umgehend</li><li>Verluste, die durch unsachgemäße Kontoverwaltung entstehen, gehen zu Ihren Lasten</li></ul><h3 id="konto-loschung" tabindex="-1">Konto-Löschung <a class="header-anchor" href="#konto-loschung" aria-label="Permalink to &quot;Konto-Löschung&quot;">​</a></h3><p>Sie können jederzeit die Löschung Ihres Kontos beantragen. Nach der Löschung werden Ihre persönlichen Daten innerhalb von 30 Tagen gelöscht, aber öffentlich veröffentlichte Inhalte möglicherweise noch erhalten bleiben.</p><h2 id="_3-verhaltensregeln-fur-benutzer" tabindex="-1">3. Verhaltensregeln für Benutzer <a class="header-anchor" href="#_3-verhaltensregeln-fur-benutzer" aria-label="Permalink to &quot;3. Verhaltensregeln für Benutzer&quot;">​</a></h2><p>Bei der Nutzung dieser Plattform stimmen Sie zu, folgende Handlungen zu unterlassen:</p><ul><li>Veröffentlichung von illegalen, schädlichen, bedrohlichen, belästigenden, verleumderischen oder urheberrechtsverletzenden Inhalten</li><li>Vortäuschen einer anderen Person oder falsche Angaben zu Ihrer Identität machen</li><li>Unbefugter Zugriff auf Konten oder Systeme anderer Personen</li><li>Störung oder Unterbrechung des ordnungsgemäßen Betriebs der Dienste</li><li>Verwenden von Automatisierungstools, um Inhalte großflächig zu extrahieren (ausgenommen angemessene API-Nutzung)</li><li>Verwenden von Tutorial-Inhalten für kommerzielle Zwecke ohne Einhaltung der Lizenzvereinbarung</li></ul><h2 id="_4-geistiges-eigentum" tabindex="-1">4. Geistiges Eigentum <a class="header-anchor" href="#_4-geistiges-eigentum" aria-label="Permalink to &quot;4. Geistiges Eigentum&quot;">​</a></h2><h3 id="open-source-lizenzhinweise" tabindex="-1">Open-Source-Lizenzhinweise <a class="header-anchor" href="#open-source-lizenzhinweise" aria-label="Permalink to &quot;Open-Source-Lizenzhinweise&quot;">​</a></h3><ul><li><strong>Tutorial-Inhalte</strong>: Unterliegen der <a href="https://creativecommons.org/licenses/by-nc-sa/4.0/" target="_blank" rel="noreferrer">CC-BY-NC-SA 4.0</a>-Lizenz, die nicht-kommerzielles Teilen und Anpassen gestattet, wobei eine Namensnennung erforderlich ist und die Inhalte unter gleichen Bedingungen geteilt werden müssen</li><li><strong>Website-Aufbau</strong>: Dieses Projekt basiert auf <a href="https://vitepress.dev/" target="_blank" rel="noreferrer">VitePress</a> und folgt der MIT-Lizenz</li><li><strong>Benutzerbeiträge</strong>: Von Ihnen eingereichte Inhalte werden standardmäßig für die Nutzung durch die Plattform unter Einhaltung der oben genannten Vereinbarungen lizenziert</li></ul><p>Die Marken, Logos und andere Brand-Identitäten von OpenCodeDocs sind gesetzlich geschützt und dürfen ohne Genehmigung nicht verwendet werden.</p><h2 id="_5-haftungsausschluss" tabindex="-1">5. Haftungsausschluss <a class="header-anchor" href="#_5-haftungsausschluss" aria-label="Permalink to &quot;5. Haftungsausschluss&quot;">​</a></h2><ul><li><strong>Dienstunterbrechung</strong>: Wir garantieren keine unterbrechungsfreie oder fehlerfreien Dienste. Wir übernehmen keine Haftung für Dienstunterbrechungen, die durch Wartung, Upgrades oder höhere Gewalt verursacht werden</li><li><strong>Inhaltsgenauigkeit</strong>: Die Tutorial-Inhalte dienen nur als Referenz. Wir garantieren nicht deren Verwendbarkeit in allen Umgebungen</li><li><strong>Verwendungsrisiko von Code</strong>: Sie gehen das Risiko ein, Code aus den Tutorials auszuführen. Es wird empfohlen, Tests in einer isolierten Umgebung durchzuführen</li><li><strong>Externe Links</strong>: Diese Website möglicherweise Links zu Websites Dritter enthalten. Wir übernehmen keine Verantwortung für deren Inhalte</li></ul><h2 id="_6-anderungen-an-der-vereinbarung" tabindex="-1">6. Änderungen an der Vereinbarung <a class="header-anchor" href="#_6-anderungen-an-der-vereinbarung" aria-label="Permalink to &quot;6. Änderungen an der Vereinbarung&quot;">​</a></h2><p>Wir können diese Vereinbarung jederzeit ändern. Die geänderte Vereinbarung wird auf der Website veröffentlicht und Ihnen wie folgt mitgeteilt:</p><ul><li>Bekanntmachung an einer hervorgehobenen Stelle auf der Website</li><li>Senden einer Benachrichtigung an die registrierte E-Mail-Adresse (falls zutreffend)</li></ul><p>Die weitere Nutzung unserer Dienste bedeutet, dass Sie die geänderte Vereinbarung akzeptieren. Wenn Sie den Änderungen nicht zustimmen, stellen Sie die Nutzung der Dienste ein.</p><h2 id="_7-streitbeilegung" tabindex="-1">7. Streitbeilegung <a class="header-anchor" href="#_7-streitbeilegung" aria-label="Permalink to &quot;7. Streitbeilegung&quot;">​</a></h2><ul><li><strong>Anwendbares Recht</strong>: Diese Vereinbarung unterliegt den Gesetzen der Volksrepublik China</li><li><strong>Streitbeilegung</strong>: Die Parteien sollten versuchen, Streitigkeiten gütlich beizulegen. Scheitert die gütliche Einigung, kann jede Partei beim Volksgericht mit Zuständigkeit am Wohnsitz des Beklagten Klage einreichen</li></ul><h2 id="_8-kontaktinformationen" tabindex="-1">8. Kontaktinformationen <a class="header-anchor" href="#_8-kontaktinformationen" aria-label="Permalink to &quot;8. Kontaktinformationen&quot;">​</a></h2><p>Wenn Sie Fragen zu dieser Vereinbarung haben, kontaktieren Sie uns bitte unter:</p><ul><li><strong>E-Mail</strong>: <a href="mailto:vbgatecom@gmail.com" target="_blank" rel="noreferrer">vbgatecom@gmail.com</a></li><li><strong>GitHub</strong>: <a href="https://github.com/vbgate/opencodedocs" target="_blank" rel="noreferrer">vbgate/opencodedocs</a></li></ul>',32)])])}const b=n(a,[["render",s]]);export{c as __pageData,b as default};
